final:
module top_module(C, obf_A, B, OP);output reg [31:0] C;
input [31:0] obf_A, B;
input [1:0] OP;

always @ (obf_A or B or OP) 
begin
	if (OP == 2'b00) begin
		C = obf_A + B;
	end
	else if (OP == 2'b01) begin
		C = obf_A & B;
	end
	else if (OP == 2'b10) begin
		C = obf_A | B;
	end
	else begin
		C = ~obf_A;
	end
end

endmodule
